const IMGS = {
  "1000190160": "data:image/jpeg;base64,",
  "1000190164": "data:image/jpeg;base64,",
  "1000190155": "data:image/jpeg;base64,",
  "1000190157": "data:image/jpeg;base64,",
  "1000190163": "data:image/jpeg;base64,",
  "1000190162": "data:image/jpeg;base64,",
  "1000190159": "data:image/jpeg;base64,",
  "1000190156": "data:image/jpeg;base64,",
};

// Inyectar imágenes al cargar
document.addEventListener('DOMContentLoaded', () => {
  document.querySelectorAll('img[data-img]').forEach(img => {
    const key = img.getAttribute('data-img');
    if (IMGS[key]) img.src = IMGS[key];
  });
  const heroBg = document.querySelector('.hero-bg-img img');
  // hero img ya tiene data-img, se maneja arriba
});
